:root {
  --color-card-bg: #ffffff;
  --color-header-bg: #2d6a4f;
  --color-header-text: #ffffff;
  --color-stall-number: #95d5b2;
  --color-stall-name: #ffffff;
  --color-badge-bg: #95d5b2;
  --color-badge-text: #1b4332;
  --color-divider: #e0e0e0;
  --color-item-bg: #f8fdf9;
  --color-item-featured-bg: #d8f3dc;
  --color-item-featured-border: #52b788;
  --color-item-border: #e8f5e9;
  --color-produce-name: #2d3a2e;
  --color-produce-price: #2d6a4f;
  --color-footer-bg: #f0faf3;
  --color-footer-border: #c8e6c9;
  --color-dot-primary: #52b788;
  --color-dot-accent: #f4a261;
  --color-tag-text: #4a6741;
  --color-hours-text: #7a9e7e;
}

.market-card {
  background-color: var(--color-card-bg);
  border-radius: 16px;
  width: 460px;
  overflow: hidden;
  border: 1px solid var(--color-divider);
}

.card-header {
  background-color: var(--color-header-bg);
  padding: 16px 20px;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.header-left {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.stall-number {
  font-size: 11px;
  font-weight: 600;
  color: var(--color-stall-number);
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

.stall-name {
  font-size: 20px;
  font-weight: 700;
  color: var(--color-stall-name);
  margin: 0;
  line-height: 1.2;
}

.open-badge {
  background-color: var(--color-badge-bg);
  color: var(--color-badge-text);
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 0.1em;
  padding: 4px 10px;
  border-radius: 20px;
}

.divider {
  height: 1px;
  background-color: var(--color-divider);
}

.produce-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 10px;
  padding: 14px 16px;
}

.produce-item {
  background-color: var(--color-item-bg);
  border: 1px solid var(--color-item-border);
  border-radius: 10px;
  padding: 10px 12px;
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.produce-item.featured {
  background-color: var(--color-item-featured-bg);
  border-color: var(--color-item-featured-border);
}

.produce-icon {
  font-size: 22px;
  line-height: 1;
}

.produce-name {
  font-size: 13px;
  font-weight: 600;
  color: var(--color-produce-name);
  line-height: 1.3;
}

.produce-price {
  font-size: 13px;
  font-weight: 700;
  color: var(--color-produce-price);
}

.card-footer {
  background-color: var(--color-footer-bg);
  border-top: 1px solid var(--color-footer-border);
  padding: 10px 16px;
  display: flex;
  align-items: center;
  gap: 16px;
}

.footer-tag {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 12px;
  font-weight: 500;
  color: var(--color-tag-text);
}

.tag-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background-color: var(--color-dot-primary);
  flex-shrink: 0;
}

.tag-dot.accent {
  background-color: var(--color-dot-accent);
}

.footer-hours {
  margin-left: auto;
  font-size: 12px;
  font-weight: 600;
  color: var(--color-hours-text);
}
